    ('PL', '829', 2022, 'Altera o art. 129 do Decreto-Lei nº 2.848, de 7 de dezembro de 1940 (Código Penal), e o art. 1º da Lei nº 8.072, de 25 de julho de 1990, para incluir o parentesco civil na causa de aumento de pena de lesão corporal praticada contra autoridade ou agente descrito nos arts. 142 e 144 da Constituição Federal, integrantes do sistema prisional ou da Força Nacional de Segurança Pública, bem como para incluir no rol dos crimes hediondos a lesão corporal dolosa de natureza gravíssima e lesão corporal seguida de morte quando praticadas contra parentes por afinidade dos referidos agentes ou autoridades.', 'Senado', '152627', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/152627', 'flavio-bolsonaro-senado-completo-autoria-substantiva-2019-2026-20260506', 'inventario_completo_senado_autoria_substantiva_2019_2026_20260506', '{"proposicao_id_api":"152627","descricao_identificacao":"PL 829/2022","data_apresentacao":"2022-04-05","casa":"SF","codigo_parlamentar_senado":5894,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"PL","uf_autor_no_protocolo":"RJ","autor_nome":"Flávio Bolsonaro","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/5894/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/152627.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/152627.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/152627","coverage_id":"flavio-bolsonaro-senado-completo-autoria-substantiva-2019-2026-20260506","coverage_scope":"inventario_completo_senado_autoria_substantiva_2019_2026_20260506","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"flavio-bolsonaro-senado-lote-a-20260506","snapshot_consulta_em":"2026-05-06T11:31:13.560Z"}'::