    ('PL', '4597', 2025, 'Altera o Decreto-Lei nº 2.848, de 7 de dezembro de 1940 (Código Penal), para incluir como qualificadora do crime de homicídio o uso de drones ou dispositivos remotos ou automatizados que dificultem ou impossibilitem a defesa da vítima; modifica a Lei nº 10.826, de 22 de dezembro de 2003 (Estatuto do Desarmamento), para agravar condutas relacionadas ao uso de armamento com drones ou tecnologia autônoma; e altera a Lei nº 11.343, de 23 de agosto de 2006 (Lei de Drogas), para aumentar a pena em casos de crimes cometidos com o emprego desses meios tecnológicos.', 'Senado', '170485', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/170485', 'flavio-bolsonaro-senado-completo-autoria-substantiva-2019-2026-20260506', 'inventario_completo_senado_autoria_substantiva_2019_2026_20260506', '{"proposicao_id_api":"170485","descricao_identificacao":"PL 4597/2025","data_apresentacao":"2025-09-16","casa":"SF","codigo_parlamentar_senado":5894,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"PL","uf_autor_no_protocolo":"RJ","autor_nome":"Flávio Bolsonaro","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/5894/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/170485.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/170485.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/170485","coverage_id":"flavio-bolsonaro-senado-completo-autoria-substantiva-2019-2026-20260506","coverage_scope":"inventario_completo_senado_autoria_substantiva_2019_2026_20260506","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"flavio-bolsonaro-senado-lote-a-20260506","snapshot_consulta_em":"2026-05-06T11:31:13.560Z"}'::jsonb),
